// ── V2 Task Envelope: task_id propagation ─────────────────────────────────────
const _env = (typeof $input !== 'undefined' && $input.all()[0].json) || {};
const _envBody = _env.body || {};
const _inherited_task_id = _envBody.task_id || null;
const _gen_task_id = () => 'tid-' + Date.now().toString(36) + '-' + Math.random().toString(36).slice(2, 9);
const _task_id = _inherited_task_id || _gen_task_id();
// ── End V2 Task Envelope ────────────────────────────────────────────────────────

const src = $input.all()[0];
// ── Loop prevention guard ────────────────────────────────────────────────────
const _incomingBody = (src.json && src.json.body) ? src.json.body : {};
const _attemptCount = (_incomingBody.attempt_count !== undefined)
    ? parseInt(_incomingBody.attempt_count, 10) || 0 : 0;
if (_attemptCount >= 1) {
    return [{ json: { loop_detected: true, original_task: _incomingBody,
        bot_name: 'cro',
        task: 'loop_escalation', user_text: null, chat_id: null, from_agent: 'loop_guard',
        now_iso: new Date().toISOString(), daily_spec: [], weekly_spec: [] } }];
}
// ── End loop prevention ──────────────────────────────────────────────────────

const messageId = (src.json && src.json.message && src.json.message.message_id)
    ? String(src.json.message.message_id) : null;

let task = 'scheduled_tick';
let user_text = null;
let chat_id = null;
let from_agent = 'system';

if (src.json && src.json.message && src.json.message.text) {
    task = 'user_dm';
    user_text = src.json.message.text;
    chat_id = src.json.message.chat && src.json.message.chat.id;
    from_agent = 'telegram';
} else if (src.json && src.json.body && src.json.body.from_agent) {
    task = 'agent_invoke';
    user_text = src.json.body.user_text || src.json.body.objective || null;
    chat_id = src.json.body.chat_id || null;
    from_agent = src.json.body.from_agent;
}

const now = new Date();
const now_iso = now.toISOString();

return [{ json: {
    bot_name: 'cro',
    task,
    user_text,
    chat_id,
    from_agent,
    now_iso,
    message_id: messageId,
    daily_spec: [],
    weekly_spec: [],
    task_id: _task_id,
} }];

const _buildTask = $('Build task payload').first().json;
if (_buildTask.loop_detected) {
    return [{ json: {
        message: JSON.stringify({ reply_text: '', actions: [{ type: 'no_op', payload: {
            reason: 'loop_detected', attempt_count: (_buildTask.original_task && _buildTask.original_task.attempt_count) || 1
        }}]}),
        session_id: 'bridge-loop-guard-' + Date.now(),
        task_kind: 'loop_escalation', user_chat_id: null,
        bot_name: _buildTask.bot_name || 'unknown', _pre_formed: true
    }}];
}

const task = $('Build task payload').first().json;
// ── CRO: Query project memory for gating decisions ──────────────────────────
let _historicalContext = { similar_projects: [], rejection_count: 0, auto_block: false, semantic_matches: [] };
const _isCroReview = task.task === 'agent_invoke' && (task.user_text || '').includes('cro_review_request');
const _projectNameForQuery = (() => {
    try {
        const _body = JSON.parse(task.user_text || '{}');
        return _body.project_name || _body.subject || task.user_text || '';
    } catch(e) { return task.user_text || ''; }
})();
if (_projectNameForQuery && _projectNameForQuery.length > 5) {
    try {
        const _memResp = await $http.post(
            `${$env.SUPER_AGENT_URL || 'https://super-agent-production.up.railway.app'}/webhook/memory-query`,
            { project_name: _projectNameForQuery, api_key: $env.N8N_API_KEY || '' }
        );
        if (_memResp && _memResp.data) {
            _historicalContext = _memResp.data;
        }
        if (_historicalContext.auto_block === true && _isCroReview) {
            return [{ json: {
                message: JSON.stringify({
                    reply_text: `🚫 AUTO-BLOCK: Project "${_projectNameForQuery}" has been rejected ${_historicalContext.rejection_count} time(s) previously. CRO auto-blocking. CEO override required.`,
                    actions: [{ type: 'memo', payload: {
                        to_agent: 'bizdev', memo_type: 'cro_rejected',
                        priority: 'high',
                        subject: `CRO AUTO-BLOCK: ${_projectNameForQuery}`,
                        body_json: {
                            project_name: _projectNameForQuery,
                            cro_score: 0, recommendation: 'REJECT',
                            reason: 'auto_block_repeated_rejection',
                            rejection_count: _historicalContext.rejection_count,
                            next_action: 'Requires CEO override to proceed. Do not resubmit without fundamentally different value proposition.',
                            attempt_count: 0
                        }
                    }}]
                }),
                session_id: `bridge-cro-${Date.now()}`,
                task_kind: 'auto_block', user_chat_id: task.chat_id,
                bot_name: task.bot_name, _pre_formed: true
            }}];
        }
    } catch(e) { /* non-blocking — memory query failure does not stop CRO execution */ }
}


const inboxRow = $('Fetch open inbox').first().json || {};
const inbox = Array.isArray(inboxRow.open_inbox) ? inboxRow.open_inbox : [];
const ctxRow = $('Fetch bot context').first().json || {};
const ctx = ctxRow.context ? [ctxRow.context] : [ctxRow];

const globalProtocol = `

GLOBAL OPERATING PROTOCOL (non-negotiable):
1. ALWAYS respond in valid JSON only. No prose, no markdown outside JSON strings.
2. EXACT response structure: {"reply_text": "...", "actions": [...]}
3. reply_text: human-readable Telegram message. Brief, role-appropriate.
4. actions: array of {type, payload} objects. Empty array if no actions.
5. NEVER include PLACEHOLDER, PASTE_, TBD, INSERT_HERE values in any field.
6. NEVER mention internal tools (n8n, shell, SQL, workflow IDs) in reply_text.
7. If required data is missing return no_op with status need_input + list exact missing fields.
8. If blocked escalate to Chief of Staff. NEVER retry autonomously.
9. MAX_RETRIES = 1. If attempt_count >= 1 in incoming body_json return no_op immediately.
`;

const system = "You are Bridge_ChiefRevenueOptimizer_BOT (CRO), the revenue intelligence engine and commercial gatekeeper of Bridge Digital Solutions.\n\nWORKFLOW POSITION (mandatory enforcement):\n  BizDev \u2192 [CRO GATE] \u2192 Security \u2192 CEO\n  Every project proposal with revenue > $0 MUST pass CRO scoring before reaching Security or CEO.\n  Score < 50  \u2192 REJECT: send memo type 'cro_rejected' to bizdev, log to project_memory\n  Score 50-69 \u2192 REVISE: send memo type 'cro_revision_needed' to bizdev with specific improvements required\n  Score \u2265 70  \u2192 APPROVE: send memo type 'cro_approved' to chief_sec_off for security clearance\n\nGATE MODE \u2014 triggered by memo_type='cro_review_request':\n1. Extract project_name from body_json. Query historical memory via the context block.\n2. If historical_context shows auto_block=true (rejected \u2265 2x) \u2192 immediately REJECT with reason='auto_block_repeated_rejection'.\n3. If similar past success found \u2192 boost score by up to +10 pts (document this in historical_comparison).\n4. If similar past failure found \u2192 reduce score by up to -15 pts (document the lesson applied).\n5. Score the proposal using the SCORING RUBRIC below (0-100).\n6. Reply with memo_type='cro_review_complete' containing the full CRO Revenue Optimization Report.\n7. Also send memo_type='cro_evaluation_record' to chief_of_staff for audit trail.\n\nSCORING RUBRIC (total 100 pts):\n  Revenue model clarity:          0-20 pts\n  Market size & timing:           0-15 pts\n  Pricing competitiveness:        0-15 pts\n  Funnel conversion realism:      0-15 pts\n  Historical success alignment:   0-15 pts (from memory context)\n  Risk-adjusted margin:           0-20 pts\n\nREQUIRED OUTPUT for cro_review_complete memo body_json:\n{\n  \"project_name\": \"...\",\n  \"cro_score\": 0-100,\n  \"revenue_model\": \"...\",\n  \"estimated_monthly_revenue_usd\": 0,\n  \"growth_potential\": \"low|medium|high|exponential\",\n  \"revenue_risks\": [...],\n  \"optimization_suggestions\": {\n    \"pricing_strategy\": \"...\",\n    \"upsells\": \"...\",\n    \"funnel_improvements\": \"...\",\n    \"automation_opportunities\": \"...\"\n  },\n  \"historical_comparison\": {\n    \"similar_projects\": [...],\n    \"outcome\": \"...\",\n    \"lessons_applied\": \"...\"\n  },\n  \"recommendation\": \"APPROVE|REVISE|REJECT\",\n  \"next_action\": \"...\"\n}\n\nMONITORING MODE \u2014 triggered by scheduled_tick:\n  - Flag leads at risk of going cold (no interaction > 5 days after demo)\n  - Identify top 3 upsell opportunities in existing paying clients\n  - Propose one pricing experiment per week (A/B test, bundle, urgency offer)\n  - Track and report: pipeline value, avg deal size, win rate, churn rate\n\nREVENUE OKRs (track weekly):\n  - Pipeline coverage ratio: 3x monthly revenue target\n  - Lead response time: < 2 hours\n  - Demo-to-close rate: > 25%\n  - Monthly churn: < 5%\n\nREVENUE SIGNALS TO MONITOR (from DB queries):\n  - bridge.leads WHERE status IN ('proposal_sent','demo_done') AND updated_at < NOW() - INTERVAL '7d'\n  - bridge.billing_records WHERE revenue_usd > 0\n  - bridge.workflow_events WHERE event_type = 'client_interaction'\n\nESCALATE TO CEO WHEN:\n  - A deal > $500 goes cold without follow-up\n  - Churn rate exceeds 5% in any 30-day window\n  - A pricing experiment shows > 20% conversion uplift\n  - A client signals expansion opportunity\n\nINTERACTION RULES:\n  - Send revenue signals and recommendations as memos to CEO and COS\n  - Coordinate with BizDev to qualify new pipeline entries\n  - Work with Finance to understand margin on proposed deals\n  - Never directly contact clients \u2014 route through PM or COS\n\nOUTPUT STYLE: Data-driven, concise. Lead with the number, then the action. Every recommendation must include projected revenue impact and confidence level.";

const contextBlock = JSON.stringify({
    now: task.now_iso,
    bot: task.bot_name,
    task_kind: task.task,
    open_inbox: inbox,
    bot_context: ctx,
    historical_context: _historicalContext,
    daily_cadence: task.daily_spec,
    weekly_cadence: task.weekly_spec,
}, null, 2);

const taskBlock = task.task === 'user_dm'
    ? `The user sent you this message on Telegram:\n${task.user_text}\n\nRespond helpfully and consider issuing actions if appropriate.`
    : task.task === 'scheduled_tick'
      ? `This is a scheduled cadence run. Scan for revenue signals, cold leads, upsell opportunities, and churn risk. Report insights to CEO/COS.`
      : `An inter-agent invocation arrived from '${task.from_agent}': ${task.user_text || 'no message body'}. Decide how to respond.`;

const outputGuard = `\n\n[OUTPUT FORMAT]\nReturn ONLY a JSON object (no prose, no markdown fences):\n{\n  "reply_text": "<Telegram message or empty string>",\n  "actions": [\n    {"type": "memo",     "payload": {"to_agent": "ceo|chief_of_staff|bizdev|finance", "memo_type": "revenue_signal|upsell_opportunity|churn_risk|pricing_experiment|status", "priority": "urgent|high|normal|low", "subject": "...", "body_json": {...}}},\n    {"type": "query",    "payload": {"sql": "<safe single SELECT>"}},\n    {"type": "escalate", "payload": {"subject": "...", "body_json": {...}}},\n    {"type": "no_op",    "payload": {"reason": "..."}}\n  ]\n}\nKeep actions <= 5.`;

const fullMessage = `${system}${globalProtocol}\n\n[CONTEXT]\n${contextBlock}\n\n[TASK]\n${taskBlock}${outputGuard}`;

return [{ json: {
    message: fullMessage,
    session_id: `bridge-cro-${task.now_iso.slice(0,16).replace(/[:T-]/g,'')}`,
    task_kind: task.task,
    user_chat_id: task.chat_id,
    bot_name: task.bot_name,
} }];

// Passthrough — bot-engine already parsed, validated, and risk-annotated the response.
const _upstream = $('Assemble prompt').first().json;
if (_upstream && _upstream._pre_formed) {
    let _pfActions;
    try { _pfActions = JSON.parse(_upstream.message).actions; } catch(e) { _pfActions = []; }
    return [{ json: {
        reply_text: '',
        actions: [{ type: 'no_op', risk: 'low',
            payload: (_pfActions[0] && _pfActions[0].payload) || { reason: 'loop_guard' } }],
        bot_name: _upstream.bot_name, user_chat_id: _upstream.user_chat_id,
        task_kind: 'loop_escalation', model_used: 'loop_guard', parse_error: null
    }}];
}
const upstream = $('Assemble prompt').first().json;
return [{ json: {
    reply_text:  $json.reply_text  || '',
    actions:     Array.isArray($json.actions) ? $json.actions : [],
    model_used:  $json.model_used  || 'unknown',
    parse_error: $json.parse_error || null,
    bot_name:    upstream.bot_name,
    user_chat_id: upstream.user_chat_id,
    task_kind:   upstream.task_kind,
} }];

const p = $json;
const out = [];
for (const a of (p.actions || [])) {
    out.push({ json: {
        action_type: a.type,
        action_risk: a.risk,
        action_payload: a.payload,
        bot_name: p.bot_name,
        user_chat_id: p.user_chat_id,
        task_kind: p.task_kind,
        model_used: p.model_used,
        reply_text: p.reply_text,
    }});
}
// Always emit at least one item so the reply path runs even when no actions.
if (out.length === 0) {
    out.push({ json: {
        action_type: 'no_op',
        action_risk: 'low',
        action_payload: { reason: 'no actions from LLM' },
        bot_name: p.bot_name,
        user_chat_id: p.user_chat_id,
        task_kind: p.task_kind,
        model_used: p.model_used,
        reply_text: p.reply_text,
    }});
}
return out;

